import { useNavigate } from "react-router-dom";
import { useState } from "react";

export default function JoinHome() {
  const navigate = useNavigate();

  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");

  const handleJoin = () => {
    if (!username.trim() || !password.trim()) {
      setError("please enter a username and password");
      return;
    }

    setError("");

    navigate("/home-ready", {
      state: {
        type: "join",
        username: username.trim(),
      },
    });
  };

  return (
    <main className="min-h-screen bg-[#eadbc9] flex items-center justify-center px-6">
      <section className="w-full max-w-[1200px] flex flex-col items-center text-center -mt-14">
        <h1
          className="text-[#6b4b3e] font-semibold tracking-[0.01em] mb-14"
          style={{
            fontSize: "clamp(3rem, 5.3vw, 5.2rem)",
            lineHeight: 1,
            fontFamily: '"Trebuchet MS", "Segoe UI", sans-serif',
          }}
        >
          join home
        </h1>

        <div className="w-full flex flex-col items-center gap-8">
          <input
            type="text"
            value={username}
            onChange={(e) => setUsername(e.target.value)}
            placeholder="username"
            className="w-full max-w-[530px] h-[76px] rounded-[18px] bg-[#f2eded] px-7 text-[1.85rem] text-[#7c695f] placeholder:text-[#9b908b] outline-none shadow-[inset_0_0_0_1px_rgba(90,62,54,0.08)]"
            style={{ fontFamily: '"Trebuchet MS", "Segoe UI", sans-serif' }}
          />

          <input
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            placeholder="password"
            className="w-full max-w-[530px] h-[76px] rounded-[18px] bg-[#f2eded] px-7 text-[1.85rem] text-[#7c695f] placeholder:text-[#9b908b] outline-none shadow-[inset_0_0_0_1px_rgba(90,62,54,0.08)]"
            style={{ fontFamily: '"Trebuchet MS", "Segoe UI", sans-serif' }}
          />

          {error ? (
            <p className="text-[#8b4b45] text-lg -mt-2 mb-1">{error}</p>
          ) : null}

          <button
            onClick={handleJoin}
            className="mt-1 w-[340px] h-[78px] rounded-[22px] bg-[#aab095] text-[#43332c] text-[2.15rem] leading-none shadow-[inset_0_0_0_1px_rgba(90,62,54,0.28)] hover:brightness-[0.98] active:translate-y-[1px] transition"
            style={{ fontFamily: '"Trebuchet MS", "Segoe UI", sans-serif' }}
          >
            join
          </button>
        </div>
      </section>
    </main>
  );
}
